import React, { useState } from 'react';
import { Post, ChatMessage, User } from '../types';
import { HeartIcon, ChatIcon, ShareIcon, CameraIcon, VideoIcon, SendIcon } from './Icons';

interface SocialHubProps {
  currentUser: User;
}

const SocialHub: React.FC<SocialHubProps> = ({ currentUser }) => {
  const [activeTab, setActiveTab] = useState<'feed' | 'chat'>('feed');
  const [posts, setPosts] = useState<Post[]>([
    { id: '1', author: 'سارة علي', authorHandle: '@sara_99', content: 'وصلت للمستوى 20! اللعبة تصبح أصعب 🤯', likes: 15, comments: 3, avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Sara', timeAgo: 'منذ دقيقتين' },
    { id: '2', author: 'خالد عمر', authorHandle: '@khaled_pro', content: 'هل يمكن لأحد مساعدتي في مسألة التفاضل؟', likes: 8, comments: 12, avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Khaled', timeAgo: 'منذ 15 دقيقة' },
    { id: '3', author: 'نورة', authorHandle: '@noura_x', content: 'تطبيق رائع جداً للأطفال 👍', image: 'https://picsum.photos/400/200', likes: 42, comments: 5, avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=Noura', timeAgo: 'منذ ساعة' },
  ]);
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'النظام', text: 'مرحباً بك في الدردشة العامة!', timestamp: new Date(), isMe: false, type: 'text' }
  ]);
  const [inputMsg, setInputMsg] = useState('');
  const [newPostContent, setNewPostContent] = useState('');

  const handlePostSubmit = () => {
    if (!newPostContent.trim()) return;
    if (currentUser.dailyPostsRemaining <= 0 && !currentUser.isSubscribed) {
        alert("تجاوزت الحد اليومي للنشر المجاني. يرجى الاشتراك للمزيد.");
        return;
    }
    const newPost: Post = {
        id: Date.now().toString(),
        author: currentUser.name,
        authorHandle: currentUser.username,
        content: newPostContent,
        likes: 0,
        comments: 0,
        avatar: currentUser.avatar,
        timeAgo: 'الآن'
    };
    setPosts([newPost, ...posts]);
    setNewPostContent('');
  };

  const handleSendMessage = () => {
    if (!inputMsg.trim()) return;
    const newMsg: ChatMessage = {
        id: Date.now().toString(),
        sender: currentUser.name,
        text: inputMsg,
        timestamp: new Date(),
        isMe: true,
        type: 'text'
    };
    setMessages([...messages, newMsg]);
    setInputMsg('');

    setTimeout(() => {
        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            sender: 'لاعب عشوائي',
            text: 'أهلاً بك! 👋',
            timestamp: new Date(),
            isMe: false,
            type: 'text'
        }]);
    }, 1500);
  };

  const handleShare = async (postContent: string) => {
    const shareData = {
        title: 'تطبيق Challenges - تحديات',
        text: postContent,
        url: 'https://ai.studio/apps/drive/1n2HFmRXFpWVmLwapYQUGvQG0B1eyTFXW'
    };

    try {
        if (navigator.share) {
            await navigator.share(shareData);
        } else {
            // Fallback for browsers that don't support navigator.share
            navigator.clipboard.writeText(shareData.url);
            alert('تم نسخ رابط التطبيق للحافظة لأن المتصفح لا يدعم المشاركة المباشرة.');
        }
    } catch (err) {
        console.error('Error sharing:', err);
    }
  };

  return (
    <div className="h-full flex flex-col bg-secondary">
      {/* Top Tabs */}
      <div className="flex bg-white sticky top-0 z-20 shadow-sm px-4 pt-2">
        <button 
            onClick={() => setActiveTab('feed')}
            className={`flex-1 pb-3 text-sm font-bold text-center transition border-b-2 ${activeTab === 'feed' ? 'text-primary border-primary' : 'text-gray-400 border-transparent'}`}
        >
            المنشورات
        </button>
        <button 
            onClick={() => setActiveTab('chat')}
            className={`flex-1 pb-3 text-sm font-bold text-center transition border-b-2 ${activeTab === 'chat' ? 'text-primary border-primary' : 'text-gray-400 border-transparent'}`}
        >
            الدردشة العامة
        </button>
      </div>

