                             <div className="w-16 h-16 rounded-full border-2 border-primary p-0.5">
                                <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${i}`} className="w-full h-full rounded-full bg-gray-100" />
                             </div>
                             <span className="text-xs font-medium text-gray-600">لاعب {i}</span>
                        </div>
                    ))}
                </div>

                {/* Create Post */}
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
