                        <p className="text-gray-700 mb-4 text-sm leading-relaxed">{post.content}</p>
                        {post.image && (
                            <div className="mb-4 rounded-xl overflow-hidden shadow-sm">
                                <img src={post.image} alt="post" className="w-full object-cover" />
