                                className="flex items-center gap-2 text-gray-400 hover:text-green-500 transition text-xs font-bold mr-auto"
                            >
                                <ShareIcon className="w-4 h-4" /> مشاركة
                            </button>
                        </div>
                    </div>
                ))}
            </div>
        ) : (
            <div className="flex flex-col h-full bg-slate-50">
                <div className="flex-1 p-4 space-y-3">
                    {messages.map(msg => (
                        <div key={msg.id} className={`flex ${msg.isMe ? 'justify-start' : 'justify-end'}`}>
                            <div className={`max-w-[85%] p-3 shadow-sm text-sm ${
                                msg.isMe 
                                    ? 'bg-primary text-white rounded-2xl rounded-tr-none' 
                                    : 'bg-white text-gray-800 rounded-2xl rounded-tl-none'
                                }`}>
                                {!msg.isMe && (
                                    <p className="text-[10px] font-bold opacity-50 mb-1 text-primary flex items-center">
                                        {msg.sender}
                                        <PlanBadge plan={msg.plan} />
                                    </p>
                                )}
                                {msg.text}
                                <div className={`text-[10px] mt-1 text-right ${msg.isMe ? 'text-blue-100' : 'text-gray-400'}`}>
                                    {msg.timestamp.toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
                <div className="p-3 bg-white border-t border-gray-100 flex gap-2 sticky bottom-0 items-center">
                    <button className="p-2 text-gray-400 hover:text-primary transition rounded-full hover:bg-gray-50">
                        <CameraIcon className="w-5 h-5" />
                    </button>
                    <input 
                        type="text" 
                        value={inputMsg}
                        onChange={(e) => setInputMsg(e.target.value)}
                        placeholder="اكتب رسالة..."
                        className="flex-1 bg-gray-100 rounded-full px-4 py-2.5 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 transition"
                        onKeyDown={(e) => e.key === 'Enter' && handleSendMessage()}
                    />
                    <button 
                        onClick={handleSendMessage}
                        className="p-2 bg-primary text-white rounded-full w-10 h-10 flex items-center justify-center hover:bg-primary-dark transition shadow-md"
                    >
                        <SendIcon className="w-4 h-4 rotate-180" />
                    </button>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

