const PlanBadge: React.FC<{ plan?: PlanType }> = ({ plan }) => {
    if (!plan || plan === 'free') return null;
    const badge = PLAN_FEATURES[plan]?.badge;
    if (!badge) return null;
    return <span className="mr-1 text-sm" title={plan}>{badge}</span>;
};

