    };

    try {
        if (navigator.share) {
            await navigator.share(shareData);
        } else {
            navigator.clipboard.writeText(shareData.url);
            alert('تم نسخ رابط التطبيق للحافظة لأن المتصفح لا يدعم المشاركة المباشرة.');
        }
