                                +
                            </div>
                        </div>
                        <span className="text-xs font-medium text-gray-600">قصتي</span>
                    </div>
                    {[1, 2, 3, 4, 5].map(i => (
                        <div key={i} className="flex flex-col items-center gap-1 min-w-[64px]">
