                                <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${i}`} className="w-full h-full rounded-full bg-gray-100" />
                             </div>
                             <span className="text-xs font-medium text-gray-600">لاعب {i}</span>
                        </div>
                    ))}
                </div>

                {/* Create Post */}
                <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100">
                    <div className="flex gap-3 mb-3">
                        <img src={currentUser.avatar} className="w-10 h-10 rounded-full bg-gray-100" />
                        <textarea 
                            value={newPostContent}
                            onChange={(e) => setNewPostContent(e.target.value)}
                            placeholder={`بماذا تفكر؟ (متبقي ${currentUser.dailyPostsRemaining > 100 ? '∞' : currentUser.dailyPostsRemaining} منشور)`}
                            className="flex-1 bg-gray-50 rounded-xl p-3 text-sm focus:outline-none focus:ring-1 focus:ring-primary resize-none h-12 transition-all focus:h-24"
                        />
                    </div>
                    <div className="flex justify-between items-center px-1">
                        <div className="flex gap-3">
                            <button className="text-gray-400 hover:text-green-500 transition">
                                <CameraIcon className="w-5 h-5" />
                            </button>
                            <button className="text-gray-400 hover:text-blue-500 transition">
                                <VideoIcon className="w-5 h-5" />
                            </button>
                        </div>
                        <button 
                            onClick={handlePostSubmit}
                            className="bg-primary text-white px-5 py-1.5 rounded-full text-xs font-bold hover:bg-primary-dark transition shadow-lg shadow-blue-100 flex items-center gap-1"
