                            <SendIcon className="w-3 h-3 rotate-180" />
                            نشر
                        </button>
                    </div>
                </div>

                {/* Posts Feed */}
                {posts.map(post => (
                    <div key={post.id} className="bg-white p-5 rounded-2xl shadow-[0_2px_15px_rgb(0,0,0,0.03)] border border-gray-50 animate-fade-in">
