                            >
                                <HeartIcon className={`w-4 h-4 ${post.isLiked ? 'fill-current' : ''}`} /> {post.likes} أعجبني
                            </button>
                            <button 
                                onClick={() => setExpandedPostId(expandedPostId === post.id ? null : post.id)}
